+
+let aspectId = 0;
+
+/** Creates a named view over two or more non-relation traits. */
+export function createAspect<const T extends readonly [AspectInput, AspectInput, ...AspectInput[]]>(
+    ...inputs: T
+): Aspect<FlattenAspects<T>> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else {
+            if (isRelation(input)) throw new Error('Koota: Relations cannot be aspect constituents.');
+            traits.push(input);
+        }
+    }
+
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+    for (const trait of traits) {
+        for (const field of Object.keys(trait.schema as Schema)) {
+            if (fields.has(field))
+                throw new Error(`Koota: Aspect constituents overlap on field "${field}".`);
+            fields.add(field);
+            schema[field] = (trait.schema as Record<string, unknown>)[field];
+        }
+    }
+
+    return Object.freeze({ [$aspect]: true as const, id: aspectId++, traits: Object.freeze(traits), schema: Object.freeze(schema) }) as Aspect<FlattenAspects<T>>;
+}
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function hasAspect(entity: { has(trait: Trait): boolean }, aspect: Aspect) {
+    return aspect.traits.every((trait) => entity.has(trait));
+}
+
+export function getAspect(entity: { get(trait: Trait): object | undefined }, aspect: Aspect): AspectRecord<Aspect> | undefined {
+    const value: Record<string, unknown> = {};
+    for (const trait of aspect.traits) {
+        const data = entity.get(trait);
+        if (data === undefined) return undefined;
+        Object.assign(value, data);
+    }
+    return value as AspectRecord<Aspect>;
